     4|
     5|use Closure;
     6|use Illuminate\Http\Request;
     7|use Illuminate\Support\Facades\Storage;
     8|use Symfony\Component\HttpFoundation\Response;
     9|use Illuminate\Contracts\Encryption\DecryptException;
    10|
    11|class AuthApiToken
    12|{
    13|    /**
    14|     * Handle an incoming request.
    15|     *
    16|     * @param  \Closure(\Illuminate\Http\Request): (\Symfony\Component\HttpFoundation\Response)  $next
    17|     */
    18|    public function handle(Request $request, Closure $next): Response
    19|    {
    20|        if (!Storage::disk('local')->exists('files/apiKey.json')) {
    21|            return response([
    22|                'message' => 'Unautorized',
    23|            ], 401);
    24|        }
    25|
    26|        $data = json_decode(decrypt(Storage::disk('local')->get('files/apiKey.json')), true);
    27|
    28|        try {
    29|            if (decrypt(request()->header('client-id')) != $data['client_id']) {
    30|                $this->logRequest(false, 'invalid_client_id');
    31|
    32|                return response([
    33|                    'message' => 'Unautorized',
    34|                ], 401);
    35|            }
    36|
    37|            if (decrypt(request()->header('client-secret')) != $data['client_secret']) {
    38|                $this->logRequest(false, 'invalid_client_secret');
    39|
    40|                return response([
    41|                    'message' => 'Unautorized',
    42|                ], 401);
    43|            }
    44|        } catch (DecryptException $th) {
    45|            $this->logRequest(false, 'decrypt_exception');
    46|
    47|            return response([
    48|                'message' => 'Unautorized',
    49|            ], 401);
    50|        }
    51|
    52|        $this->logRequest(true);
    53|
    54|        return $next($request);
    55|    }
    56|
    57|    public function logRequest($isAuthorized, $unauthorizedReason = null)
    58|    {
    59|        if (request()->route()->uri == 'api/backup/stats' || request()->route()->uri == 'api/backup/callback') {
    60|            return;
    61|        }
    62|
    63|        $date = now()->format('Y-m-d');
    64|
    65|        if (Storage::disk('local')->exists('files/apiAccessLog.json')) {
    66|            $contents = Storage::disk('local')->get('files/apiAccessLog.json');
    67|            $data = json_decode($contents, true);
    68|        } else {
    69|            $data = [];
    70|        }
    71|
    72|        $data[] = [
    73|            'date' => now()->format('Y-m-d'),
    74|            'timestamp' => now()->toIso8601String(),
    75|            'ip_address' => request()->ip(),
    76|            'endpoint' => url()->current(),
    77|            'authorized' => $isAuthorized,
    78|            'unauthorized_reason' => $unauthorizedReason,
    79|        ];
    80|
    81|        Storage::disk('local')->put('files/apiAccessLog.json', json_encode($data));
    82|    }
