{"content": "     1|<?php
     2|
     3|namespace App\Helpers;
     4|
     5|class EncryptedFileHelper
     6|{
     7|    private const NONCE_LENGTH = SODIUM_CRYPTO_SECRETBOX_NONCEBYTES;
     8|    private const KEY_LENGTH = SODIUM_CRYPTO_SECRETBOX_KEYBYTES;
     9|
    10|    /**
    11|     * Krypter filinnhold med autentisert kryptering (XSalsa20 + Poly1305).
    12|     *
    13|     * @param string $fileContents Binært innhold fra fil
    14|     * @param string $base64Key Base64-kodet 256-bit nøkkel fra nøkkelfil
    15|     * @param array|null $metadata Valgfri metadata (f.eks. filnavn, mime)
    16|     * @return string Base64-kodet streng: nonce + ciphertext
    17|     */
    18|    public static function encrypt(string $fileContents, string $base64Key, ?array $metadata = null): string
    19|    {
    20|        $key = base64_decode($base64Key, true);
    21|
    22|        if ($key === false || strlen($key) !== self::KEY_LENGTH) {
    23|            throw new \InvalidArgumentException("Ugyldig nøkkel.");
    24|        }
    25|
    26|        $nonce = random_bytes(self::NONCE_LENGTH);
    27|
    28|        // Inkluder metadata hvis oppgitt
    29|        $payload = $metadata
    30|            ? json_encode(['__meta__' => $metadata]) . "\n\n" . $fileContents
    31|            : $fileContents;
    32|
    33|        $cipher = sodium_crypto_secretbox($payload, $nonce, $key);
    34|
    35|        sodium_memzero($key);
    36|        sodium_memzero($payload);
    37|
    38|        return base64_encode($nonce . $cipher);
    39|    }
    40|
    41|    /**
    42|     * Dekrypter kryptert fil og valgfritt hent metadata.
    43|     *
    44|     * @param string $encodedData Base64-kodet data (nonce + ciphertext)
    45|     * @param string $base64Key Base64-kodet nøkkel
    46|     * @param bool $extractMetadata Returner metadata og innhold som array
    47|     * @return array|string|null
    48|     */
    49|    public static function decrypt(string $encodedData, string $base64Key, bool $extractMetadata = false): array|string|null
    50|    {
    51|        $data = base64_decode($encodedData, true);
    52|
    53|        if ($data === false || strlen($data) < self::NONCE_LENGTH + 1) {
    54|            return null;
    55|        }
    56|
    57|        $key = base64_decode($base64Key, true);
    58|        
    59|        if ($key === false || strlen($key) !== self::KEY_LENGTH) {
    60|            return null;
    61|        }
    62|
    63|        $nonce = substr($data, 0, self::NONCE_LENGTH);
    64|        $cipher = substr($data, self::NONCE_LENGTH);
    65|
    66|        $decrypted = sodium_crypto_secretbox_open($cipher, $nonce, $key);
    67|
    68|        sodium_memzero($key);
    69|
    70|        if ($decrypted === false) {
    71|            return null;
    72|        }
    73|
    74|        // Sjekk om metadata er inkludert
    75|        if ($extractMetadata && str_starts_with($decrypted, '{"__meta__":')) {
    76|            [$metaJson, $content] = explode("\n\n", $decrypted, 2);
    77|            $metadata = json_decode($metaJson, true)['__meta__'] ?? [];
    78|
    79|            return [
    80|                'content' => $content,
    81|                'metadata' => $metadata,
    82|            ];
    83|        }
    84|
    85|        return $decrypted;
    86|    }
    87|}
