     6|use Illuminate\Support\Str;
     7|use Illuminate\Bus\Queueable;
     8|use App\Helpers\PasscodeFileHelper;
     9|use App\Helpers\EncryptedFileHelper;
    10|use App\Exceptions\PasscodeException;
    11|use Intervention\Image\Facades\Image;
    12|use Illuminate\Queue\SerializesModels;
    13|use Illuminate\Support\Facades\Storage;
    14|use Illuminate\Queue\InteractsWithQueue;
    15|use Illuminate\Contracts\Queue\ShouldQueue;
    16|use Illuminate\Foundation\Bus\Dispatchable;
    17|
    18|class EncryptAndMoveProfileAvatar implements ShouldQueue
    19|{
    20|    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
    21|
    22|    protected $profileId;
    23|
    24|    /**
    25|     * Create a new job instance.
    26|     */
    27|    public function __construct($profileId)
    28|    {
    29|        $this->profileId = $profileId;
    30|    }
    31|
    32|    /**
    33|     * Execute the job.
    34|     */
    35|    public function handle(): void
    36|    {
    37|        $profile = Profile::where('id', $this->profileId)->firstOrFail();
    38|
    39|        if ($profile->profile_picture_path == null) {
    40|            return;
    41|        }
    42|
    43|        $content = Storage::disk('backblaze')->get($profile->profile_picture_path);
    44|
    45|        $img = Image::make($content);
    46|
    47|        try {
    48|            $passcode = (new PasscodeFileHelper)();
    49|        } catch (PasscodeException $th) {
    50|            $this->release(60);
    51|            return;
    52|        }
    53|
    54|        $encrypted = EncryptedFileHelper::encrypt($img->encode('jpg', 100), $passcode);
    55|
    56|        $imageUuid = $this->extractUuid($profile->profile_picture_path);
    57|
    58|        $path = "encrypted/avatars/{$profile->id}/{$imageUuid}.enc";
    59|
    60|        Storage::disk('backblaze')->put($path, $encrypted);
    61|
    62|        sodium_memzero($content);
    63|        sodium_memzero($encrypted);
    64|        sodium_memzero($passcode);
    65|
    66|        if (!Storage::disk('backblaze')->exists($path)) {
    67|            $this->release(10);
    68|            return;
    69|        }
    70|
    71|        Storage::disk('backblaze')->delete($profile->profile_picture_path);
    72|
    73|        $profile->profile_picture_path = null;
    74|        $profile->avatar = $imageUuid;
    75|        $profile->save();
    76|    }
    77|
    78|    protected function extractUuid($filePath)
    79|    {
    80|        if (preg_match('/avatar\/\d+\/([a-f0-9\-]+)\.(jpg|png)$/', $filePath, $matches)) {
    81|            return $matches[1];
    82|        }
    83|        return null;
    84|    }
